import React from "react"
import Template from "../templates/about"
import { graphql, PageProps } from "gatsby"

const AboutPage = ({ data, location }: PageProps<Data>) => {
  return <Template data={data} location={location} />
}

export default AboutPage

type Data = {
  site: {
    siteMetadata: {
      title: string
    }
  }
  allFile: {
    edges: {
      node: {
        childMarkdownRemark: {
          excerpt: string
          frontmatter: {
            title: string
            date: string
            description: string
          }
          fields: {
            slug: string
          }
        }
      }
    }[]
  }
}

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allFile(
      filter: {
        sourceInstanceName: { eq: "pages" }
        internal: { mediaType: { eq: "text/markdown" } }
        childMarkdownRemark: { fields: { slug: { eq: "/about/" } } }
      }
    ) {
      edges {
        node {
          childMarkdownRemark {
            html
            fields {
              slug
            }
            frontmatter {
              date(formatString: "MMMM DD, YYYY")
              title
              description
            }
          }
        }
      }
    }
  }
`
